  /*shortcodes*/
  public function getIdModuleCategory($categoryId) { 
	$query = $this->db->query("SELECT DISTINCT lm.code FROM " . DB_PREFIX . "layout_module lm LEFT JOIN " . DB_PREFIX . "category_to_layout ctl ON ctl.layout_id = lm.layout_id WHERE ctl.category_id = '" . (int)$categoryId . "' AND lm.position = 'column_right' AND (lm.code LIKE 'html%' OR lm.code LIKE 'banner%')");

	if ($query->num_rows) {
		$moduleId = Array();

		foreach ($query->rows as $module) {
			list($type, $id) = explode('.', $module["code"]);
			$moduleId[] = $id;
		}

		return $moduleId;

	} else {
		return false;
	}
}
