/*shortcodes*/

  /*shortcodes*/
  public function getShortcodesContent($moduleIdList) {
	$moduleIdListStr = implode(",", $moduleIdList);

	$query = $this->db->query("SELECT md.setting FROM " . DB_PREFIX . "module md WHERE md.module_id IN (" . $this->db->escape($moduleIdListStr) . ") AND md.name LIKE 'sc_%' AND (md.code = 'html' OR md.code = 'banner')");

	$moduleData = Array();

	if ($query->num_rows) {	 

		foreach($query->rows as $item) {$moduleData[] = $item['setting'];}
		return $moduleData;

	} else {
		return false;
	}
}
